思路：双指针
使用双指针统计每个相同请求地址的连续区间，记录起始位置、结束位置，并累计该区间总响应时间。
对每个连续区间计算：
首次索引
连续次数
平均响应时间
按出现顺序保存结果并返回。
C++
#include<iostream>
#include<vector>
#include<string>
#include <utility>
#include <sstream>
#include<algorithm>
#include<cmath>
#include<map>
using namespace std;
//
通用 切割函数 函数 将字符串
str
根据
delimiter
进行切割
vector<string> split(const
string& str, const string& delimiter) {
vector<string>
result;
size_t start = 0;
size_t end =
str.find(delimiter);
while (end !=
string::npos) {
result.push_back(str.substr(start, end - start));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(str.substr(start));
return result;
}
//
统计函数
vector<vector<int>>
hanle(vector<string> path, vector<int> responseTime) {
vector<vector<int>> res;
int n = path.size();
for (int i = 0; i <
n; ) {
int totalTime = responseTime[i];
int j = i;
//
获取相同路径起始和终止连续位置
while (j + 1< n && path[j] == path[j+1]) {
totalTime += responseTime[j+1];
j++;
}
res.push_back({i, j - i + 1, totalTime / (j - i + 1)});
i = j + 1;
}
return res;
}
int main() {
string pathInput;
string responseInput;
getline(cin, pathInput);
getline(cin,
responseInput);
vector<string>
paths = split(pathInput, ",");
vector<int>
responseTime(paths.size());
vector<string> tmp
= split(responseInput, ",");
for (int i = 0; i <
tmp.size(); i++) {
responseTime[i] = stoi(tmp[i]);
}
vector<vector<int>> res = hanle(paths, responseTime);
//
输出结果
for (int i = 0; i <
res.size(); i++) {
cout << res[i][0] << "," << res[i][1] <<
"," << res[i][2];
if (i != res.size() -1) {
cout << " ";
}
}
return 0;
}
Java
import java.util.*;
public class Main {
//
统计函数
static List<int[]>
hanle(List<String> path, List<Integer> responseTime) {
List<int[]> res = new ArrayList<>();
int n = path.size();
for (int i = 0; i < n;) {
int totalTime = responseTime.get(i);
int j = i;
//
获取相同路径起始和终止连续位置
while (j + 1 < n && path.get(j).equals(path.get(j + 1))) {
totalTime += responseTime.get(j + 1);
j++;
}
res.add(new int[]{i, j - i + 1, totalTime / (j - i + 1)});
i = j + 1;
}
return res;
}
